Actionscript.script:
function 后撤步移动(慢速度, 快速度)
{
	if (_parent.方向 == "右")
	{
		_parent.移动("右",慢速度);
	}
	else if (_parent.方向 == "左")
	{
		_parent.移动("左",慢速度);
	}
	if (random(2) == 0)
	{
		_parent.移动("上",快速度);
	}
	else
	{
		_parent.移动("下",快速度);
	}
}

function 攻击时四向移动(上, 下, 左, 右)
{
	if (上 != 0)
	{
		_parent.移动("上",上);
	}
	else if (下 != 0)
	{
		_parent.移动("下",下);
	}
	if (左 != 0)
	{
		_parent.方向改变("左");
		_parent.移动("左",左);
	}
	else if (右 != 0)
	{
		_parent.方向改变("右");
		_parent.移动("右",右);
	}
}
敌方目标 = _root.gameworld[_parent.攻击目标];
距离X = _parent._x - 敌方目标._x;
if (Math.abs(距离X) < 200)
{
	gotoAndPlay("诛杀步");
}
else if (random(2) == 0)
{
	gotoAndPlay("诛杀步");
}
else
{
	gotoAndPlay("后撤步");
}
_parent.攻击呐喊();

//本帧是锁定敌人位置的帧，建议比位移元件早一些。

//你需要改的值，追踪持续帧是从挂载ef的位移元件的第二帧到预计实际到达敌人位置时的总帧数。
速度上限 = _parent.行走X速度 * 6;
速度下限 = _parent.行走X速度 * 3;
追踪持续帧 = 6;

//自动计算的值
敌方目标 = _root.gameworld[_parent.攻击目标];
上速度 = 0;
下速度 = 0;
左速度 = 0;
右速度 = 0;
距离X = _parent._x - 敌方目标._x;
速度X = Math.min(Math.max(距离X / 追踪持续帧, -速度上限), 速度上限);

if (速度X >= 0)
{
	速度X = Math.max(速度X, 速度下限);
	左速度 = 速度X;
}
else
{
	速度X = Math.min(速度X, -速度下限);
	右速度 = -速度X;
}
距离Z = _parent.Z轴坐标 - 敌方目标.Z轴坐标;
速度Z = 速度X * 距离Z / 距离X;
if (速度Z >= 0)
{
	上速度 = Math.min(速度Z, 速度上限 * 2);
}
else
{
	下速度 = Math.min(-速度Z, 速度上限 * 2);
}

//以下为带追踪的位移代码。如需启用Z轴追踪，则在"追踪代码"图层启用相关代码
onClipEvent(enterFrame){
   _parent.攻击时四向移动(_parent.上速度, _parent.下速度, _parent.左速度, _parent.右速度);
}

/*如果无需追踪，则使用类似以下位移代码即可
onClipEvent(enterFrame){
   _parent.攻击时移动(_parent._parent.行走X速度 * 1.5,_parent._parent.行走X速度 * 1.5);
}
*/
